import i18n from 'i18next';
import { initReactI18next } from 'react-i18next';

import en from './locales/en.json';
import es from './locales/es.json';
import fr from './locales/fr.json';
import de from './locales/de.json';
import ja from './locales/ja.json';

const resources = {
  en: { translation: en },
  es: { translation: es },
  fr: { translation: fr },
  de: { translation: de },
  ja: { translation: ja },
};

i18n
  .use(initReactI18next)
  .init({
    resources,
    lng: localStorage.getItem('appLanguage') || 'en',
    fallbackLng: 'en',
    interpolation: { escapeValue: false },
    react: { useSuspense: false },
    parseMissingKeyHandler: (key) => key,
  });

// Safe localStorage saver (won't crash in private mode)
const saveLanguage = (lng) => {
  try {
    localStorage.setItem('appLanguage', lng);
    document.documentElement.lang = lng;
  } catch (e) { console.warn('localStorage write failed:', e); }
};

i18n.on('languageChanged', saveLanguage);

// Export safe change function
export const safeChangeLanguage = async (lng) => {
  if (!resources[lng]) lng = 'en';
  try {
    await i18n.changeLanguage(lng);
    return { success: true };
  } catch (err) {
    console.warn('Language change handled gracefully:', err);
    return { success: false };
  }
};

export default i18n;
